event_handlers:
onCtaClick:(cta) => {
  switch (cta.actionType) {
    case 'request_quote':
      window.location.href = 'contact.html?source=home&intent=request_quote';
      break;
    case 'start_project_brief':
      window.location.href = 'contact.html?source=home&intent=start_project_brief';
      break;
    case 'configure_popup':
      window.location.href = 'popup_configurator.html?source=home';
      break;
    default:
      // For any future or custom actionType, fall back to contact with generic intent
      window.location.href = 'contact.html?source=home&intent=' + encodeURIComponent(cta.actionType);
  }
}

onTileClick:(category) => {
  if (category && category.slug) {
    const params = new URLSearchParams({ serviceId: category.slug, source: 'home_featured' });
    window.location.href = 'service_category.html?' + params.toString();
  }
}

onCardClick:(servicePackage) => {
  if (servicePackage && servicePackage.id) {
    const params = new URLSearchParams({ servicePackageId: servicePackage.id, source: 'home_flagship' });
    window.location.href = 'service_package.html?' + params.toString();
  }
}

onRequestQuoteClick:(servicePackage) => {
  if (servicePackage && servicePackage.id) {
    const params = new URLSearchParams({
      source: 'home_flagship',
      intent: 'request_quote',
      servicePackageId: servicePackage.id
    });
    window.location.href = 'contact.html?' + params.toString();
  }
}

onCaseStudyClick:(caseStudy) => {
  if (caseStudy && caseStudy.id) {
    const params = new URLSearchParams({ caseStudyId: caseStudy.id, source: 'home_featured' });
    window.location.href = 'case_study_detail.html?' + params.toString();
  }
}

onViewAllClick:() => {
  const params = new URLSearchParams({ source: 'home_featured' });
  window.location.href = 'case_studies.html?' + params.toString();
}

onEventClick:(event) => {
  if (event && event.id) {
    const params = new URLSearchParams({ eventId: event.id, source: 'home_events' });
    window.location.href = 'event_detail.html?' + params.toString();
  }
}

onViewAllClick:() => {
  const params = new URLSearchParams({ source: 'home_events' });
  window.location.href = 'events.html?' + params.toString();
}

onQuickActionClick:(cta) => {
  // Delegate to the same navigation logic used in hero-actions
  if (!cta || !cta.actionType) return;
  switch (cta.actionType) {
    case 'request_quote':
      window.location.href = 'contact.html?source=home_quick_actions&intent=request_quote';
      break;
    case 'start_project_brief':
      window.location.href = 'contact.html?source=home_quick_actions&intent=start_project_brief';
      break;
    case 'configure_popup':
      window.location.href = 'popup_configurator.html?source=home_quick_actions';
      break;
    default:
      window.location.href = 'contact.html?source=home_quick_actions&intent=' + encodeURIComponent(cta.actionType);
  }
}

onInit:() => {
  const params = new URLSearchParams(window.location.search);
  const section = params.get('section');
  if (!section) return;
  // After data load, scroll to the requested section if it exists
  // Implementation depends on the presence of anchors or refs for each section.
}

onInPageNavClick:(targetSection) => {
  const params = new URLSearchParams(window.location.search);
  params.set('section', targetSection);
  const newUrl = window.location.pathname + '?' + params.toString();
  window.history.pushState({}, '', newUrl);
  // Then scroll/focus to the section corresponding to targetSection.
}

